@function grid($units, $counter)
      $half-gutter: false
      @if $counter == 0
        $half-gutter: true
      @if $counter > $columns
        $counter: 1
      @if $counter < 1
        $counter: 1

      $grid-return: 0 // zero out grid return

      // Left to right grid
      @if $scale-grid-direction == ltr
        @for $i from 1 through $units
          $grid-return: $grid-return + nth($ms-grid-list, abs($columns - $counter) + 1)
          // the only difference between rtl and ltr is this
          $counter: $counter + 1
          @if $i == $units
            @if $counter == 0
              $half-gutter: true
            @if $half-gutter
              @return $grid-return - ($calculated-gutter / 2)
            @return $grid-return - $calculated-gutter


      // Right to left grid
      @if $scale-grid-direction == rtl
        @for $i from 1 through $units
          $grid-return: $grid-return + nth($ms-grid-list, $counter)
          // the only difference between rtl and ltr is this
          $counter: $counter + 1
          @if $i == $units
            @if $counter == 0
              $half-gutter: true
            @if $half-gutter
              @return $grid-return - ($calculated-gutter / 2)
            @return $grid-return - $calculated-gutter

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  float: left
  width: grid-span($span, $location, $columns, $gutter)

  // add special left padding
  @if type-of($columns) == list
    @if type-of(nth($columns, $location)) == list
      padding-left: nth(nth($columns, $location), 2)
      +box-sizing(border-box)
    @else if $padding != 0
      padding-left: $padding
      +box-sizing(border-box)
    // add special right padding
    @if type-of(nth($columns, ($location + $span - 1))) == list
      padding-right: nth(nth($columns, ($location + $span - 1)), 2)
      +box-sizing(border-box)
    @else if $padding != 0
      padding-right: $padding
      +box-sizing(border-box)

  @else
    +grid-padding($padding)

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
  @if $padding != 0
    +grid-padding($padding)

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  float: left
  width: grid-span($span, $location, $columns, $gutter)

  // add special left padding
  @if type-of(nth($columns, $location)) == list
    padding-left: nth(nth($columns, $location), 2)
  @elseif $padding != 0
    padding-left: $padding
  // add special right padding
  @if type-of(nth($columns, ($location + $span - 1))) == list
    padding-right: nth(nth($columns, ($location + $span - 1)), 2)
  @elseif $padding != 0
    padding-right: $padding

  // if no special padding, apply box sizing, else apply regular padding
  @if type-of(nth($columns, $location)) or type-of(nth($columns, ($location + $span - 1))) == list
    +box-sizing(border-box)
  @else
    +grid-padding($padding)

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
  @if $padding != 0
    +grid-padding($padding)

