  width: grid-span($span, $location, $columns, $gutter)
  $box-sizing: false

  // add special left padding
  @if type-of($columns) == list
    @if type-of(nth($columns, $location)) == list
      padding-left: nth(nth($columns, $location), 2)
      $box-sizing: true
    @else if $padding != 0
      padding-left: $padding
      $box-sizing: true
    // add special right padding
    @if type-of(nth($columns, ($location + $span - 1))) == list
      padding-right: nth(nth($columns, ($location + $span - 1)), 2)
      $box-sizing: true
    @else if $padding != 0
      padding-right: $padding
      $box-sizing: true

  @else if $padding != 0
    padding: 0 $padding
    $box-sizing: true

  @if $box-sizing
    +box-sizing(border-box)

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
    float: right
    margin-right: 0
    @if $rtl
      [dir="rtl"] &
        float: left
        margin-left: 0
  @else
    float: left
    margin-right: $gutter
    @if $rtl
      [dir="rtl"] &
        float: right
        margin-right: 0
        margin-left: $gutter

=structure-float($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $grouped-styles: false)
  @if $dir == ltr or $dir == both
    @if $location > 1 and $location < column-count($columns)
      margin-right: -100%
      float: left
      margin-left: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      margin-right: -100%
      float: left
      margin-left: 0
    @if $location == column-count($columns)
      float: right
      margin-right: 0
  @if $dir == rtl
    @if $location > 1 and $location < column-count($columns)
      margin-left: -100%
      float: right
      margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      margin-left: -100%
      float: right
      margin-right: 0
    @if $location == column-count($columns)
      float: left
      margin-left: 0
  @if $dir == both
    #{$rtl-selector} &
      @if $location > 1 and $location < column-count($columns)
        margin-left: -100%
        float: right
        margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
      @if $location == 1
        margin-left: -100%
        float: right
        margin-right: 0
      @if $location == column-count($columns)
        float: left
        margin-left: 0
